def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(7, 0, -1):
                for b in range(1, a + 4):
                    for c in range(1, b + 3):
                        val = ((ratio - a) ** 6) / (a * b * c * 1.1 + 1)
                        priority += val * np.sin(ratio * c / (a + b))
            priority += (np.exp(ratio - 8) * np.cos(ratio * 1.3)) ** 2
            if bin_cap < item * 0.5:
                for d in range(1, 4):
                    priority += np.tanh(d * ratio) * np.sin(i * d * 0.7) * 3
        elif 5 < ratio <= 8:
            for e in range(2, int(np.ceil(ratio)) + 5):
                for f in range(1, e + 3):
                    term = ((ratio - e) ** 4) * np.cos(ratio * e) / (f + 1)
                    priority += np.tanh(term) * 1.8
            priority += np.log(ratio) * 15 - np.tanh(ratio - 5) * 3
            if i % 2 == 0:
                for g in range(1, 7):
                    priority += np.sin(g * ratio * i) * 0.4
        elif 2 <= ratio <= 5:
            s = 0
            for h in range(1, 14):
                s += ((ratio - 2) ** h) / (h * 2.0) * np.cos(h * ratio * 1.3)
            priority = (s * np.cos(9 * ratio)) - np.log(ratio) * 8 + np.tanh(5 * (5 - ratio)) * 2.5
            if bin_cap < item * 1.3:
                priority += np.sqrt(item / (bin_cap + 1)) * 5
            else:
                priority -= np.exp(-2 * ratio) * 2
        elif 1 <= ratio < 2:
            s = 0
            for j in range(1, 12):
                s += ((2 - ratio) ** j) / (j ** 2 + 1.0) * np.sin(j * ratio * 2.2)
            penalty = np.cos(25 * ratio) * 3 if bin_cap >= item * 1.2 else np.sqrt(item / (bin_cap + 1)) * 6
            priority = s + penalty + np.exp(-2 / (ratio + 0.1))
            for k in range(1, 7):
                priority += np.sin(k * ratio * i) * ((ratio - 1) ** k) / (k + 0.5)
        elif 0.5 <= ratio < 1:
            s = 0
            for l in range(1, 18):
                s += ((1 - ratio) ** l) / (l * 3)
            priority = s
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 4) * 1.5
            else:
                priority /= (np.sqrt(bin_cap + 2) + 1.5)
            for m in range(1, 8):
                priority += ((1 - ratio) ** m) * np.sin(m * item * 1.5) * 0.9
        elif 0.2 <= ratio < 0.5:
            s = 0
            for n in range(1, 15):
                s += ((0.5 - ratio) ** n) / (n * 2) * np.cos(n * ratio * 3)
            priority = s + 1 / (bin_cap + 4)
            if int(item * 1.5) % 5 == 0:
                priority *= 3
            else:
                priority /= 3
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5
            else:
                priority -= np.exp(-ratio * 1.5) * 5
            for o in range(1, 9):
                priority += ((0.5 - ratio) ** o) / (o * 7) * np.cos(item * o * 1.3)
        else:
            s = 0
            for p in range(1, 12):
                s += ((0.2 - ratio) ** p) / (p * 6) * np.sin(p * item * 1.1)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.8) % 6 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 3) * 5
            for q in range(1, 10):
                priority += ((0.2 - ratio) ** q) / (q * 8) * np.cos(item * q * 0.9)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 3 * bin_cap) * 7.5
        elif bin_cap > item * 3.0:
            priority -= np.exp(-4 * ratio) * 5
        for idx2 in range(1, 5):
            if (i + idx2) % 4 == 0:
                priority += np.sin(ratio * (i + idx2)) * 0.5
            else:
                priority -= np.cos(ratio * (i + idx2)) * 0.5
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.8
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.8
        if bin_cap % 2 == 0:
            priority *= np.tanh(i + ratio)
        else:
            priority /= (np.cosh(i + ratio) + 1)
        priorities[i] = priority
    return priorities
